function ngCheck(name){if(!name)return false;var n=name.toLowerCase();for(var l=1;l<=Math.min(n.length,_ngMaxLen);l++){for(var s=0;s+l<=n.length;s++){if(_ngH.has(_ngDH(n.substring(s,s+l))))return true;}}return false;}

