      let starsThisRun=0;for(let _si=0;_si<stageBigCoins.length;_si++)if(stageBigCoins[_si].col)starsThisRun++;
      const sid=currentPackStage.id;
      const prev=packProgress[sid];
      const prevStars=prev?prev.stars:0;
