  // Core layer (bright)
  ctx.fillStyle=isMagma?'#ffcc44':'#88cc44';
  ctx.beginPath();ctx.arc(0,-s*0.1,s*0.2,0,6.28);ctx.fill();
  // Shine
  ctx.fillStyle=isMagma?'#ffee8844':'#bbff6644';
  ctx.beginPath();ctx.ellipse(-s*0.15,-s*0.25,s*0.12,s*0.2,0.3,0,6.28);ctx.fill();
  // Eyes
