  ctx.fillText(t('back'),35,42+safeTop);
  // Reset button
  ctx.fillStyle='#ff386022';rr(W-60,22+safeTop,50,30,8);ctx.fill();
  ctx.strokeStyle='#ff386066';ctx.lineWidth=1;rr(W-60,22+safeTop,50,30,8);ctx.stroke();
